import { ArrowLeft, Target, Layout, Image as ImageIcon, BookOpen, Star, Heart, FileText, AlertCircle, Settings, MessageCircle, User, Zap } from "lucide-react";
import { Link } from "react-router-dom";

export default function ProjectDetail() {
  const sections = [
    {
      id: 1,
      title: "制作理念",
      items: [
        {
          icon: <Target className="w-6 h-6 text-orange-500" />,
          text: "无论是强调实用价值、塑造访客氛围，还是触动情感共鸣，优秀的标题都能够有效提升文章的打开率。"
        },
        {
          icon: <Layout className="w-6 h-6 text-blue-500" />,
          text: "清晰的内容结构和逻辑提升阅读体验的关键。合理的逻辑划分能帮助读者快速建立认知框架。"
        },
        {
          icon: <ImageIcon className="w-6 h-6 text-green-500" />,
          text: "高质量的视觉素材不仅能吸引读者注意力，更能辅助文字表达，提升整体阅读沉浸感。"
        }
      ]
    },
    {
      id: 2,
      title: "成功因素",
      cards: [
        {
          icon: <BookOpen className="w-6 h-6 text-green-600" />,
          title: "选题精细，击中用户痛点",
          desc: "营造全面、实用或有趣的内容，精准吸引有需求喜欢花卉植物的用户。"
        },
        {
          icon: <Star className="w-6 h-6 text-purple-600" />,
          title: "标题吸睛，激发点击欲望",
          desc: "简述好玩的标题，概括全文介绍什么品种和植物，富有文化底蕴和美感，吸引对植物花卉感兴趣的用户群体。"
        },
        {
          icon: <Heart className="w-6 h-6 text-red-500" />,
          title: "排版精美，提升阅读体验",
          desc: "整体色调和设计元素保持一致，塑造专业、美观的视觉感受。信息结构一目了然，降低阅读疲劳，提升阅读流畅度。"
        }
      ],
      footer: "核心价值：无须采用同样结构，核心目标是降低读者的认知负载，提升获取信息的效率。"
    },
    {
      id: 3,
      title: "不足方面",
      cards: [
        {
          icon: <FileText className="w-6 h-6 text-green-600" />,
          title: "内容同质化",
          desc: "文章中的知识和观点多为行业内的常识或普遍观点的汇总，缺乏作者独特的见解和深度分析。"
        },
        {
          icon: <Zap className="w-6 h-6 text-green-600" />,
          title: "单向输出",
          desc: "内容以作者单向输出为主，缺乏与读者的互动和交流，难以建立情感连接。"
        },
        {
          icon: <AlertCircle className="w-6 h-6 text-green-600" />,
          title: "观点不够鲜明",
          desc: "在一些可以表达个人立场的选题上，观点不够鲜明，显得四平八稳，难以给读者留下深刻印象。"
        }
      ],
      footer: "总结：互动设计不足，未能有效调动用户参与，导致用户粘性低，传播范围受限。"
    },
    {
      id: 4,
      title: "优化建议：",
      cards: [
        {
          icon: <MessageCircle className="w-6 h-6 text-orange-400" />,
          title: "设置互动环节",
          desc: "在文章末尾提出开放性问题，鼓励用户在评论区留言分享自己的看法和经验。"
        },
        {
          icon: <User className="w-6 h-6 text-orange-400" />,
          title: "强化个人观点",
          desc: "在文章中鲜明地表达作者的个人观点和立场，建立独特的个人风格。"
        },
        {
          icon: <Settings className="w-6 h-6 text-orange-400" />,
          title: "打造系列内容",
          desc: "围绕特定主题打造系列文章，形成品牌效应，吸引用户持续关注。"
        }
      ],
      footer: "核心目标：通过独家内容与粉丝建立深度共鸣，提升用户粘性与内容传播力。"
    }
  ];

  return (
    <div className="min-h-screen bg-white pb-20 font-sans text-[#333]">
      <div className="container max-w-4xl mx-auto px-4 py-12">
        {/* Back Button */}
        <Link to="/" className="inline-flex items-center text-green-700 font-bold mb-8 hover:gap-2 transition-all">
          <ArrowLeft className="mr-2" /> 返回首页
        </Link>

        {/* Headline */}
        <div className="mb-12">
          <h1 className="text-2xl md:text-3xl font-bold mb-8 text-black">
            一周两篇，其中三篇浏览量200+，最高浏览量600+
          </h1>
          
          {/* Thumbnails */}
          <div className="grid grid-cols-3 gap-4 mb-16">
            {[
              { id: 1, url: "https://mp.weixin.qq.com/s/oghLkRVsBuJYE4tyYRAOBA", title: "Whale Article", prompt: "white%20daisies%20with%20green%20centers%20close%20up%20floral%20photography" },
              { id: 2, url: "https://mp.weixin.qq.com/s/sukmPzHcKlxOAypG069ZLA", title: "Whale 文案", prompt: "pink%20camellia%20flower%20close%20up%20delicate%20petals%20nature%20photography" },
              { id: 3, url: "https://mp.weixin.qq.com/s/3y-QxclgS3NQoPjlPUW7Cw", title: "WhatsShare", prompt: "red%20rafflesia%20flower%20exotic%20botanical%20photography%20vibrant%20texture" }
            ].map((article) => (
              <a 
                key={article.id}
                href={article.url} 
                target="_blank" 
                rel="noopener noreferrer"
                className="bg-white p-2 rounded-lg shadow-sm hover:shadow-md transition-shadow group cursor-pointer"
              >
                <div className="aspect-[3/4] bg-white p-1.5 rounded-2xl shadow-sm overflow-hidden relative border border-lime/20">
                   <div className="w-full h-full rounded-xl overflow-hidden relative">
                     <img 
                      src={`https://coresg-normal.trae.ai/api/ide/v1/text_to_image?prompt=${article.prompt}&image_size=portrait_4_3`} 
                      alt={article.title}
                      className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"
                     />
                     <div className="absolute inset-0 bg-black/0 group-hover:bg-black/10 transition-colors flex items-center justify-center">
                        <div className="bg-lime text-black text-[10px] font-black px-4 py-2 rounded-full opacity-0 group-hover:opacity-100 transition-all transform group-hover:scale-110 flex items-center gap-2 shadow-lg">
                          <MessageCircle className="w-3.5 h-3.5 fill-black" /> 点击跳转
                        </div>
                     </div>
                   </div>
                   {/* Progress Bar Style Bottom Accent */}
                   <div className="mt-2 px-1">
                     <div className="h-1.5 w-full bg-gray-100 rounded-full overflow-hidden relative">
                        <div className="absolute top-0 left-0 h-full w-1/3 bg-lime rounded-full"></div>
                        <div className="absolute top-1/2 left-1/3 -translate-y-1/2 -translate-x-1/2 w-2.5 h-2.5 bg-white border border-gray-200 rounded-full shadow-sm z-10"></div>
                     </div>
                   </div>
                </div>
              </a>
            ))}
          </div>
        </div>

        {/* Content Sections */}
        <div className="space-y-16 relative">
          {sections.map((section) => (
            <div key={section.id} className="relative">
              {/* Section Header */}
              <div className="flex items-center gap-4 mb-8">
                <div className="w-10 h-10 rounded-full bg-green-500 flex items-center justify-center text-white font-bold text-xl">
                  {section.id}
                </div>
                <h2 className="text-2xl font-bold text-green-600">{section.title}</h2>
              </div>

              {/* Section Items/Cards */}
              {section.items ? (
                <div className="grid grid-cols-1 gap-8 items-start">
                   <div className="space-y-6">
                    {section.items.map((item, idx) => (
                      <div key={idx} className="flex gap-4 bg-white/50 p-4 rounded-xl border border-green-100">
                        <div className="shrink-0">{item.icon}</div>
                        <p className="text-sm leading-relaxed">{item.text}</p>
                      </div>
                    ))}
                   </div>
                </div>
              ) : (
                <div className="space-y-6">
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    {section.cards?.map((card, idx) => (
                      <div key={idx} className="bg-white p-6 rounded-2xl shadow-sm border border-green-100 flex flex-col gap-4">
                        <div className="w-12 h-12 rounded-xl bg-gray-50 flex items-center justify-center">
                          {card.icon}
                        </div>
                        <div>
                          <h3 className="font-bold text-lg mb-2">{card.title}</h3>
                          <p className="text-xs text-gray-500 leading-relaxed">{card.desc}</p>
                        </div>
                      </div>
                    ))}
                  </div>
                  <div className="bg-cyan-100/50 text-cyan-800 p-3 rounded-lg text-center text-xs font-bold tracking-tight">
                    {section.footer}
                  </div>
                </div>
              )}
            </div>
          ))}

          {/* Section 5: Summary */}
          <div className="relative">
            <div className="flex items-center gap-4 mb-8">
              <div className="w-10 h-10 rounded-full bg-green-500 flex items-center justify-center text-white font-bold text-xl">
                5
              </div>
              <h2 className="text-2xl font-bold text-green-600">最后总结：</h2>
            </div>
            <div className="bg-green-100/50 p-8 rounded-3xl space-y-4">
              <ul className="space-y-4 text-sm leading-relaxed">
                <li><span className="font-bold">内容要素：</span>优秀的公众号内容需具备有价值的内容、精美的视觉呈现和清晰的结构，这是吸引用户的基础。</li>
                <li><span className="font-bold">流量密码：</span>高观看量源于精准的选题定位、吸睛的标题设计以及符合阅读习惯的优秀排版。</li>
                <li><span className="font-bold">优化方向：</span>未来可重点提升内容深度、增强用户互动性，并拓展多元化的推广渠道以扩大影响力。</li>
              </ul>
            </div>
          </div>
        </div>

        {/* Footer Background Text */}
        <div className="mt-32 text-center pointer-events-none opacity-10">
          <h2 className="text-7xl md:text-[10rem] font-black text-green-600 tracking-tighter">
            THANK YOU
          </h2>
        </div>
      </div>
    </div>
  );
}
