import { useEffect, useState } from "react";
import { motion, useSpring, useMotionValue } from "framer-motion";

export function TouchParticles() {
  const mouseX = useMotionValue(0);
  const mouseY = useMotionValue(0);

  // Use springs for smooth following effect
  const springConfig = { damping: 30, stiffness: 120, mass: 0.8 };
  const cursorX = useSpring(mouseX, springConfig);
  const cursorY = useSpring(mouseY, springConfig);

  const [isVisible, setIsVisible] = useState(false);

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      mouseX.set(e.clientX);
      mouseY.set(e.clientY);
      if (!isVisible) setIsVisible(true);
    };

    const handleMouseLeave = () => setIsVisible(false);
    const handleMouseEnter = () => setIsVisible(true);

    window.addEventListener("mousemove", handleMouseMove);
    document.body.addEventListener("mouseleave", handleMouseLeave);
    document.body.addEventListener("mouseenter", handleMouseEnter);

    return () => {
      window.removeEventListener("mousemove", handleMouseMove);
      document.body.removeEventListener("mouseleave", handleMouseLeave);
      document.body.removeEventListener("mouseenter", handleMouseEnter);
    };
  }, [mouseX, mouseY, isVisible]);

  if (!isVisible) return null;

  return (
    <div className="fixed inset-0 pointer-events-none z-[-10] overflow-hidden">
      {/* Large Circular Glow - Matching Avatar Size */}
      <motion.div
        className="absolute rounded-full"
        style={{
          // Match the avatar size: clamp(240px, 40vw, 450px)
          width: "clamp(240px, 40vw, 450px)",
          height: "clamp(240px, 40vw, 450px)",
          x: cursorX,
          y: cursorY,
          translateX: "-50%",
          translateY: "-50%",
          // Radial gradient: Vibrant pink matching the button color
          background: "radial-gradient(circle, rgba(255, 0, 122, 0.7) 0%, rgba(255, 0, 122, 0.4) 40%, rgba(255, 0, 122, 0) 80%)",
          filter: "blur(40px)", // Increased blur to soften the gradient even more
        }}
      />
    </div>
  );
}
