import { Link, useLocation } from "react-router-dom";
import { Button } from "../ui/Button";
import { cn } from "../../utils/cn";
import { Menu, X } from "lucide-react";
import { useState } from "react";

const navigation = [
  { name: "Home", sub: "首页", href: "/" },
  { name: "About", sub: "关于我", href: "/about" },
  { name: "Works", sub: "我的作品", href: "/works" },
  { name: "Skills", sub: "工作技能", href: "/skills" },
  { name: "Exploration", sub: "探索", href: "/exploration" },
];

export function Header() {
  const location = useLocation();
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  return (
    <header className="sticky top-0 z-50 w-full bg-black text-white">
      <div className="container flex h-16 items-center justify-between">
        {/* Logo */}
        <Link to="/" className="flex items-center gap-2">
          <span className="text-2xl font-bold text-lime">Lara</span>
          <span className="text-xl font-bold text-white">辣辣</span>
        </Link>

        {/* Desktop Navigation */}
        <nav className="hidden md:flex items-center gap-8">
          {navigation.map((item) => (
            <Link
              key={item.name}
              to={item.href}
              className={cn(
                "group flex flex-col items-center text-sm font-medium transition-colors hover:text-lime",
                location.pathname === item.href ? "text-lime" : "text-white"
              )}
            >
              <span className="uppercase tracking-wide">{item.name}</span>
              <span className="text-[10px] opacity-70 group-hover:opacity-100">
                {item.sub}
              </span>
            </Link>
          ))}
        </nav>

        {/* CTA Button */}
        <div className="hidden md:flex">
          <a href="/resume.pdf" target="_blank" rel="noopener noreferrer">
            <Button variant="default" className="font-bold">
              Contact Me 联系我
            </Button>
          </a>
        </div>

        {/* Mobile Menu Button */}
        <button
          className="md:hidden text-white"
          onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
        >
          {isMobileMenuOpen ? <X /> : <Menu />}
        </button>
      </div>

      {/* Mobile Navigation */}
      {isMobileMenuOpen && (
        <div className="md:hidden bg-black border-t border-gray-800 p-4">
          <nav className="flex flex-col gap-4">
            {navigation.map((item) => (
              <Link
                key={item.name}
                to={item.href}
                className={cn(
                  "flex items-center justify-between py-2 text-sm font-medium transition-colors hover:text-lime",
                  location.pathname === item.href ? "text-lime" : "text-white"
                )}
                onClick={() => setIsMobileMenuOpen(false)}
              >
                <span className="uppercase">{item.name}</span>
                <span className="text-xs opacity-70">{item.sub}</span>
              </Link>
            ))}
            <a href="/resume.pdf" target="_blank" rel="noopener noreferrer" className="w-full mt-4">
              <Button className="w-full" onClick={() => setIsMobileMenuOpen(false)}>
                Contact Me 联系我
              </Button>
            </a>
          </nav>
        </div>
      )}
    </header>
  );
}
